params.command:
docker exec el34-ips bash -lc "python3 - <<'PY'
import json, datetime, collections
now = datetime.datetime.utcnow()
threshold = now - datetime.timedelta(minutes=5)
counts = collections.Counter()
with open('/var/log/suricata/eve.json') as f:
    for line in f:
        try:
            ev = json.loads(line)
        except:
            continue
        if ev.get('event_type') != 'dns':
            continue
        ts_str = ev.get('timestamp')
        if not ts_str:
            continue
        try:
            ts = datetime.datetime.strptime(ts_str, '%Y-%m-%dT%H:%M:%S.%fZ')
        except ValueError:
            try:
                ts = datetime.datetime.strptime(ts_str, '%Y-%m-%dT%H:%M:%SZ')
            except Exception:
                continue
        if ts < threshold:
            continue
        query = ev.get('dns', {}).get('query')
        if query:
            counts[query] += 1
for domain, cnt in counts.most_common():
    print(f'{domain}: {cnt}')
if any(cnt >= 100 for cnt in counts.values()):
    print('VOLUME_ANOMALY')
else:
    print('NORMAL')
PY"
